import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const statusColor = { pending: '#f59e0b', confirmed: '#10b981', cancelled: '#ef4444', completed: '#6366f1' };

export default function ProviderDashboard() {
  const { user } = useAuth();
  const [appointments, setAppointments] = useState([]);
  const [form, setForm] = useState({ name: '', description: '', duration: '', price: '', availableSlots: '' });

  useEffect(() => {
    API.get('/appointments/my').then(res => setAppointments(res.data));
  }, []);

  const handleAddService = async () => {
    try {
      const slots = form.availableSlots.split(',').map(s => s.trim());
      await API.post('/services', { ...form, availableSlots: slots });
      toast.success('Service added!');
      setForm({ name: '', description: '', duration: '', price: '', availableSlots: '' });
    } catch (err) {
      toast.error('Failed to add service');
    }
  };

  const updateStatus = async (id, status) => {
    await API.put(`/appointments/${id}/status`, { status });
    setAppointments(prev => prev.map(a => a._id === id ? { ...a, status } : a));
    toast.success(`Marked as ${status}`);
  };

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>Provider Dashboard — {user.name}</h2>

      {/* Add Service */}
      <div style={styles.section}>
        <h3>➕ Add New Service</h3>
        <div style={styles.formGrid}>
          <input style={styles.input} placeholder="Service Name" value={form.name}
            onChange={e => setForm({ ...form, name: e.target.value })} />
          <input style={styles.input} placeholder="Description" value={form.description}
            onChange={e => setForm({ ...form, description: e.target.value })} />
          <input style={styles.input} placeholder="Duration (mins)" value={form.duration}
            onChange={e => setForm({ ...form, duration: e.target.value })} />
          <input style={styles.input} placeholder="Price (₹)" value={form.price}
            onChange={e => setForm({ ...form, price: e.target.value })} />
          <input style={styles.input} placeholder="Slots (e.g. 09:00, 10:00, 11:00)" value={form.availableSlots}
            onChange={e => setForm({ ...form, availableSlots: e.target.value })} />
        </div>
        <button style={styles.btn} onClick={handleAddService}>Add Service</button>
      </div>

      {/* Appointments */}
      <div style={styles.section}>
        <h3>📋 Incoming Appointments</h3>
        {appointments.length === 0 && <p>No appointments yet.</p>}
        {appointments.map(a => (
          <div key={a._id} style={styles.card}>
            <div style={styles.row}>
              <strong>{a.service?.name}</strong>
              <span style={{ ...styles.badge, background: statusColor[a.status] }}>{a.status}</span>
            </div>
            <p>👤 Customer: {a.customer?.name} ({a.customer?.email})</p>
            <p>📅 {a.date} ⏰ {a.timeSlot}</p>
            {a.notes && <p>📝 {a.notes}</p>}
            {a.status === 'pending' && (
              <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
                <button style={styles.confirmBtn} onClick={() => updateStatus(a._id, 'confirmed')}>✅ Confirm</button>
                <button style={styles.cancelBtn} onClick={() => updateStatus(a._id, 'cancelled')}>❌ Cancel</button>
              </div>
            )}
            {a.status === 'confirmed' && (
              <button style={{ ...styles.confirmBtn, background: '#6366f1', marginTop: '10px' }}
                onClick={() => updateStatus(a._id, 'completed')}>
                Mark Completed
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

// Pending buttons — replace with these high-contrast versions
{a.status === 'pending' && (
  <>
    <button onClick={() => updateStatus(a._id, 'confirmed')}
      style={{ background:'#34d399', color:'#022c22', border:'none', padding:'8px 16px', borderRadius:'8px', cursor:'pointer', fontSize:'13px', fontWeight:700, transition:'all 0.2s' }}>
      ✅ Confirm
    </button>
    <button onClick={() => updateStatus(a._id, 'cancelled')}
      style={{ background:'#f87171', color:'#2d0000', border:'none', padding:'8px 16px', borderRadius:'8px', cursor:'pointer', fontSize:'13px', fontWeight:700 }}>
      ❌ Decline
    </button>
  </>
)}
{a.status === 'confirmed' && (
  <button onClick={() => updateStatus(a._id, 'completed')}
    style={{ background:'#818cf8', color:'#0f0c2e', border:'none', padding:'8px 18px', borderRadius:'8px', cursor:'pointer', fontSize:'13px', fontWeight:700 }}>
    🎉 Mark Complete
  </button>
)}
